2	 * Order pricing module.
3	 *
4	 * Computes the total price of an order: item subtotal, discounts, VAT, and
5	 * currency-aware rounding. The public surface is `computePrice`, the
6	 * `PricingFacade`, and the option/type exports; everything else is internal
7	 * machinery.
8	 */
9	
10	export interface OrderItem {
11	  name: string;
12	  unitPrice: number;
13	  quantity: number;
14	}
15	
16	export type Currency = "GBP" | "EUR" | "USD";
17	
18	export interface Order {
19	  items: OrderItem[];
20	  currency: Currency;
21	  loyaltyMember: boolean;
