87	
88	interface DiscountStrategy {
89	  readonly name: string;
90	  applies(order: Order): boolean;
91	  apply(subtotal: number): number;
92	}
93	
94	class BulkDiscountStrategy implements DiscountStrategy {
95	  readonly name = "bulk";
96	
97	  private totalQuantity(order: Order): number {
98	    let totalQuantity = 0;
99	    for (const item of order.items) {
100	      totalQuantity += item.quantity;
101	    }
102	    return totalQuantity;
103	  }
104	
105	  applies(order: Order): boolean {
106	    return this.totalQuantity(order) >= 10;
107	  }
108	
109	  apply(subtotal: number): number {
110	    return subtotal * 0.9;
111	  }
112	}
